{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "title": "ATS CV Screening Output Schema",
  "type": "object",
  "required": [
    "overall_fit_score",
    "fit_rating",
    "strengths",
    "gaps_weaknesses",
    "recommendations",
    "match_summary_table"
  ],
  "properties": {
    "overall_fit_score": {
      "type": "number",
      "minimum": 0,
      "maximum": 100,
      "description": "Weighted overall fit score of the candidate (0-100) calculated using ATS criteria weights and overall_strictness."
    },
    "fit_rating": {
      "type": "string",
      "enum": ["Excellent", "Strong", "Moderate", "Weak", "Not Fit"],
      "description": "Categorical rating based on overall_fit_score."
    },
    "strengths": {
      "type": "array",
      "items": { "type": "string" },
      "description": "List of candidate strengths or matched skills/projects relevant to the job."
    },
    "gaps_weaknesses": {
      "type": "array",
      "items": { "type": "string" },
      "description": "List of missing skills, certifications, experience gaps, or other mismatches."
    },
    "recommendations": {
      "type": "array",
      "items": { "type": "string" },
      "description": "Suggested improvements or steps for the candidate to better meet job requirements."
    },
    "match_summary_table": {
      "type": "object",
      "required": ["skills", "experience", "education", "certifications", "languages", "projects"],
      "properties": {
        "skills": {
          "type": "object",
          "required": ["required", "candidate", "match_score"],
          "properties": {
            "required": { "type": "array", "items": { "type": "string" } },
            "candidate": { "type": "array", "items": { "type": "string" } },
            "match_score": { "type": "number", "minimum": 0, "maximum": 100 }
          }
        },
        "experience": {
          "type": "object",
          "required": ["required_years", "candidate_years", "match_score"],
          "properties": {
            "required_years": { "type": "number", "minimum": 0 },
            "candidate_years": { "type": "number", "minimum": 0 },
            "match_score": { "type": "number", "minimum": 0, "maximum": 100 }
          }
        },
        "education": {
          "type": "object",
          "required": ["required", "candidate", "match_score"],
          "properties": {
            "required": { "type": "string" },
            "candidate": { "type": "string" },
            "match_score": { "type": "number", "minimum": 0, "maximum": 100 }
          }
        },
        "certifications": {
          "type": "object",
          "required": ["required", "candidate", "match_score"],
          "properties": {
            "required": { "type": "array", "items": { "type": "string" } },
            "candidate": { "type": "array", "items": { "type": "string" } },
            "match_score": { "type": "number", "minimum": 0, "maximum": 100 }
          }
        },
        "languages": {
          "type": "object",
          "required": ["required", "candidate", "match_score"],
          "properties": {
            "required": { "type": "array", "items": { "type": "string" } },
            "candidate": { "type": "array", "items": { "type": "string" } },
            "match_score": { "type": "number", "minimum": 0, "maximum": 100 }
          }
        },
        "projects": {
          "type": "object",
          "required": ["required", "candidate", "match_score"],
          "properties": {
            "required": { "type": "array", "items": { "type": "string" } },
            "candidate": { "type": "array", "items": { "type": "string" } },
            "match_score": { "type": "number", "minimum": 0, "maximum": 100 }
          }
        }
      }
    }
  }
}

