{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "title": "AI Evaluation Schema",
  "type": "object",
  "required": [
    "approach_score",
    "code_quality_score",
    "correctness_score",
    "communication_score",
    "overall_score",
    "ai_analysis",
    "code_review",
    "recommendation"
  ],
  "properties": {
    "approach_score": {
      "type": "number",
      "minimum": 0,
      "maximum": 100,
      "description": "Score for the candidate's approach/design of the workflow."
    },
    "code_quality_score": {
      "type": "number",
      "minimum": 0,
      "maximum": 100,
      "description": "Score for code and workflow quality, organization, and readability."
    },
    "correctness_score": {
      "type": "number",
      "minimum": 0,
      "maximum": 100,
      "description": "Score for correctness and successful execution of the workflow."
    },
    "communication_score": {
      "type": "number",
      "minimum": 0,
      "maximum": 100,
      "description": "Score for clarity in explaining workflow design and reasoning."
    },
    "overall_score": {
      "type": "number",
      "minimum": 0,
      "maximum": 100,
      "description": "Weighted overall score calculated from other criteria."
    },
    "ai_analysis": {
      "type": "object",
      "required": ["accuracy_rating", "classification", "errors", "explanation"],
      "properties": {
        "accuracy_rating": {
          "type": "number",
          "minimum": 0,
          "maximum": 100,
          "description": "Numeric rating of the video analysis accuracy."
        },
        "classification": {
          "type": "string",
          "enum": ["correct", "partially_correct", "incorrect"],
          "description": "Overall classification of the video analysis."
        },
        "errors": {
          "type": "array",
          "items": { "type": "string" },
          "description": "List of mismatches, missing points, or inaccuracies."
        },
        "explanation": {
          "type": "string",
          "description": "Summary of reasoning behind the evaluation."
        }
      }
    },
    "code_review": {
      "type": "string",
      "description": "Comments on the candidate's workflow code quality, correctness, and improvements."
    },
    "recommendation": {
      "type": "string",
      "description": ", e.g., 'pass','fail'."
    }
  },
  "additionalProperties": false
}

